import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a fixed size for the buffer
        int bufferSize = 10;

        // Ensure user input does not exceed buffer size
        String truncatedInput = userInput.substring(0, Math.min(userInput.length(), bufferSize));

        // Copy user input into buffer with proper bounds checking
        char[] buffer = new char[bufferSize];
        for (int i = 0; i < truncatedInput.length(); i++) {
            buffer[i] = truncatedInput.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
